using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.ApiTests;/// <summary>/// Good case: Create audit log with valid data/// Expected: 200 OK or 201 Created/// </summary>public class AuditServiceTests_CreateAuditLog_WithValidData_ShouldCreate : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "AuditService"    };    [SkippableFact]    public async Task CreateAuditLog_WithValidData_ShouldCreate()    {        await AuthenticateAsAdminAsync(AuditClient);        var request = new         {             action = "CREATE_EHR",             actorId = TestSeedData.DoctorUserId,             targetId = TestSeedData.PatientUserId,             targetType = "EHR",             description = "Doctor created new EHR record",             orgId = TestSeedData.HospitalAOrgId         };        var response = await PostAsJsonWithRetryAsync(AuditClient, ApiEndpoints.Audit.Create, request);        Assert.True(            response.StatusCode == HttpStatusCode.OK ||             response.StatusCode == HttpStatusCode.Created,            $"Expected 200 or 201, got {response.StatusCode}");    }}
